Here's a complete implementation:

**XAML ŌĆö `ItemsPage.xaml`**

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             xmlns:models="clr-namespace:MyApp.Models"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">

        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}"
                        EmptyView="No items found.">

            <CollectionView.ItemsLayout>
                <LinearItemsLayout Orientation="Vertical"
                                   ItemSizingStrategy="MeasureFirstItem" />
            </CollectionView.ItemsLayout>

            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*" ColumnSpacing="12">
                        <VisualStateManager.VisualStateGroups>
                            <VisualStateGroup Name="CommonStates">
                                <VisualState Name="Normal">
                                    <VisualState.Setters>
                                        <Setter Property="BackgroundColor" Value="Transparent" />
                                    </VisualState.Setters>
                                </VisualState>
                                <VisualState Name="Selected">
                                    <VisualState.Setters>
                                        <Setter Property="BackgroundColor" Value="{StaticResource Primary}" />
                                    </VisualState.Setters>
                                </VisualState>
                            </VisualStateGroup>
                        </VisualStateManager.VisualStateGroups>

                        <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                        <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}" FontSize="12" TextColor="Gray" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

**ViewModel ŌĆö `ItemsViewModel.cs`**

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

public partial class ItemsViewModel : ObservableObject
{
    private readonly IItemService _itemService;

    public ObservableCollection<Item> Items { get; } = new();

    [ObservableProperty]
    private Item? _currentItem;

    [ObservableProperty]
    private bool _isRefreshing;

    public ItemsViewModel(IItemService itemService)
    {
        _itemService = itemService;
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;

        await Shell.Current.GoToAsync(
            $"{nameof(DetailPage)}?id={CurrentItem.Id}");

        // Clear selection so the user can re-select the same item later
        CurrentItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var freshData = await _itemService.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in freshData)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false;   // hides the spinner
        }
    }
}
```

**Key binding relationships:**

| XAML property | ViewModel member | Purpose |
|---|---|---|
| `ItemsSource` | `ObservableCollection<Item> Items` | Data source; auto-updates UI on add/remove |
| `SelectedItem` (TwoWay) | `CurrentItem` | Tracks which item the user tapped |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires navigation on tap |
| `RefreshView.Command` | `RefreshCommand` | Fires API reload on pull-down |
| `RefreshView.IsRefreshing` | `IsRefreshing` | Set to `false` when done to hide spinner |

**Important details:**

- **Reset `CurrentItem` to `null`** after navigating ŌĆö otherwise tapping the same item again won't re-fire the command.
- **Set `IsRefreshing = false`** in a `finally` block so the spinner always stops, even on errors.
- **Use `ObservableCollection<T>`**, never `List<T>` ŌĆö swapping a `List` forces a full re-render.
- **`MeasureFirstItem`** improves scroll performance when rows are uniform height.
- Register the detail route in `AppShell.xaml.cs`: `Routing.RegisterRoute(nameof(DetailPage), typeof(DetailPage));`
